+
+namespace TicketClassifier.Services;
+
+public class TicketModelTrainer
+{
+    private readonly string _dataPath;
+    private readonly string _modelPath;
+    private readonly ILogger<TicketModelTrainer> _logger;
+
+    public TicketModelTrainer(ILogger<TicketModelTrainer> logger)
+    {
+        _dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
+        _modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");
+        _logger = logger;
+    }
+
+    public void TrainAndEvaluate()
+    {
+        var mlContext = new MLContext(seed: 42);
+
+        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
+            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
+
+        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
+
+        var pipeline = mlContext.Transforms.Text.FeaturizeText(
+                "SubjectFeatures", nameof(TicketInput.Subject))
+            .Append(mlContext.Transforms.Text.FeaturizeText(
+                "DescriptionFeatures", nameof(TicketInput.Description)))
+            .Append(mlContext.Transforms.Concatenate("Features",
+                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
+            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
+            .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
+            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
+                labelColumnName: "Label", featureColumnName: "Features"))
+            .Append(mlContext.Transforms.Conversion.MapKeyToValue(
